// Build today's date range for filtering Google Sheets rows
const now = new Date();
const todayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate()).toISOString();
const todayEnd = new Date(now.getFullYear(), now.getMonth(), now.getDate() + 1).toISOString();

const dateStr = now.toLocaleDateString('en-US', {
  year: 'numeric', month: 'long', day: 'numeric',
  timeZone: 'America/Chicago'
});

return [{ json: { todayStart, todayEnd, dateStr, run_at: now.toISOString() } }];

// Filter to today's signals only
const items = $input.all();
const todayStart = $('Build Today\'s Date Filter').first().json.todayStart;
const todayEnd = $('Build Today\'s Date Filter').first().json.todayEnd;

const todaySignals = items.filter(item => {
  const capturedAt = item.json.captured_at || '';
  return capturedAt >= todayStart && capturedAt < todayEnd;
});

return [{ json: {
  signals: todaySignals.map(i => i.json),
  count: todaySignals.length,
  dateStr: $('Build Today\'s Date Filter').first().json.dateStr
} }];

// formatDigest.js logic inlined
// Builds compact batch input for the premium digest synthesis call

const data = $input.first().json;
const signals = data.signals || [];

const lines = signals.map((s, i) => {
  const num = i + 1;
  const lane = s.lane || 'Unknown';
  const source = s.source || 'Unknown';
  const signalType = s.signal_type || 'Unknown';
  const cluster = s.keyword_cluster || '';
  const title = s.title || '(no title)';
  const url = s.url || '';
  const keywords = s.matched_keywords || '';

  return [
    `[${num}] LANE: ${lane} | SOURCE: ${source} | TYPE: ${signalType} | CLUSTER: ${cluster}`,
    `TITLE: ${title}`,
    `URL: ${url}`,
    `KEYWORDS: ${keywords}`,
    '',
  ].join('\n');
});

return [{
  json: {
    digest_input: lines.join('\n'),
    signal_count: signals.length,
    dateStr: data.dateStr,
  }
}];

// Parse and format digest for email
const digestData = $input.first().json;
const dateStr = $('Build Digest Input').first().json.dateStr;
const signalCount = $('Build Digest Input').first().json.signal_count;

const digestText = digestData.content?.[0]?.text || digestData.text || digestData.message?.content || 'Digest generation failed.';

// Simple HTML wrapper
const htmlBody = `
<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <style>
    body { font-family: Georgia, serif; max-width: 680px; margin: 0 auto; padding: 24px; color: #1a1a1a; }
    h1 { font-size: 22px; border-bottom: 2px solid #333; padding-bottom: 8px; }
    h2 { font-size: 16px; color: #444; margin-top: 28px; }
    p { line-height: 1.6; }
    .meta { font-size: 13px; color: #888; margin-bottom: 24px; }
    .footer { font-size: 12px; color: #aaa; border-top: 1px solid #eee; padding-top: 12px; margin-top: 32px; }
  </style>
</head>
<body>
  <h1>BizDeedz Signal Engine — Daily Digest</h1>
  <p class="meta">Date: ${dateStr} &nbsp;|&nbsp; High-Value Signals Today: ${signalCount}</p>
  <div>${digestText.replace(/\n/g, '<br>').replace(/## (.+)/g, '<h2>$1</h2>').replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')}</div>
  <div class="footer">Generated by BizDeedz Signal Engine &nbsp;|&nbsp; Powered by n8n + AI</div>
</body>
</html>`;

return [{ json: {
  subject: `BizDeedz Signal Digest — ${dateStr}`,
  htmlBody,
  plainText: digestText,
  dateStr,
  signalCount,
} }];

// Build no-signals email when collector found nothing today
const dateStr = $('Build Today\'s Date Filter').first().json.dateStr;
return [{ json: {
  subject: `BizDeedz Signal Digest — ${dateStr} (No Signals Today)`,
  htmlBody: `<html><body><p>No high-value signals were collected today (${dateStr}).</p><p>The collector ran but found no items meeting the quality threshold. This may indicate low activity in monitored sources today.</p></body></html>`,
  plainText: `No high-value signals collected today (${dateStr}).`,
} }];
